# flake.nix
{
  description = "Secure Antigravity Dev Environment";
  inputs.nixpkgs.url = "github:NixOS/nixpkgs/nixos-23.11";

  outputs = { self, nixpkgs }:
    let
      system = "x86_64-linux";
      pkgs = nixpkgs.legacyPackages.${system};
    in {
      devShells.${system}.default = pkgs.mkShell {
        buildInputs = [
          pkgs.python310
          pkgs.nodejs-18_x
          pkgs.google-chrome
        ];
        shellHook = ''
          export PATH=$PATH:~/.local/bin
          echo "Declarative Antigravity environment loaded via Nix."
        '';
      };
    };
}
